package migrate_test

import (
	"database/sql"
	"testing"

	"github.com/oklog/ulid/v2"
	"github.com/stretchr/testify/require"
)

func TestMyDataMigration(t *testing.T) {
	rowID := ulid.Make()

	runner{
		stops: stops{
			{
				// Insert seed data before the migration runs.
				// Before: 20260320084936_some-prior.up.sql
				version:   20260320084936,
				direction: directionUp,
				action: func(t *testing.T, db *sql.DB) {
					_, err := db.Exec(`INSERT INTO some_table (id, namespace, value) VALUES ($1, 'default', 'old')`, rowID.String())
					require.NoError(t, err)
				},
			},
			{
				// Assert post-migration state.
				// After: 20260401000000_my-migration.up.sql
				version:   20260401000000,
				direction: directionUp,
				action: func(t *testing.T, db *sql.DB) {
					var value string
					err := db.QueryRow(`SELECT value FROM some_table WHERE id = $1`, rowID.String()).Scan(&value)
					require.NoError(t, err)
					require.Equal(t, "new", value)
				},
			},
		},
	}.Test(t)
}
